      "tests/test_smoke.py": "from core.runner import Runner\nfrom core.config import load_config\nimport asyncio\ndef test_runner_constructs():\n    r = Runner({\"target\":\"example.com\",\"mode\":\"ai\"})\n    fs = asyncio.run(r.run())\n    assert isinstance(fs, list)\n",
