      "core/__init__.py": "",
      "core/config.py": "\"\"\"YAML config loader with safe defaults.\"\"\"\nimport os\ndef load_config(path):\n    if not os.path.exists(path):\n        return {\"timeout\": 15, \"concurrency\": 8, \"verify_tls\": True}\n    try:\n        import yaml\n        with open(path) as f: return yaml.safe_load(f) or {}\n    except ImportError:\n        # YAML missing — minimal kv parser\n        out = {}\n        for line in open(path):\n            line = line.split(\"#\",1)[0].strip()\n            if \":\" in line:\n                k,v = line.split(\":\",1); out[k.strip()] = v.strip()\n        return out\n",
      "core/runner.py": "\"\"\"Dispatches probes for the active mode and aggregates findings.\"\"\"\nimport importlib, asyncio\nPROBES = [\"docker_sock_probe\",\"k8s_rbac_probe\",\"privileged_probe\",\"admission_probe\",\"mtls_probe\"]\n\nclass Runner:\n    def __init__(self, cfg):\n        self.cfg = cfg\n        self.findings = []\n\n    async def run(self):\n        for mod_name in PROBES:\n            try:\n                mod = importlib.import_module(f\"probes.{mod_name}\")\n                res = mod.probe(self.cfg)\n                if asyncio.iscoroutine(res): res = await res\n                for r in (res or []):\n                    r.setdefault(\"probe\", mod_name)\n                    r.setdefault(\"severity\", \"INFO\")\n                    self.findings.append(r)\n            except Exception as e:\n                self.findings.append({\"probe\": mod_name, \"severity\": \"ERROR\", \"message\": f\"{type(e).__name__}: {e}\"})\n        return self.findings\n",
      "core/reporter.py": "\"\"\"Multi-format reporter.\"\"\"\nimport json, html\nclass Reporter:\n    def __init__(self, data): self.data = data\n    def render(self, fmt):\n        if fmt == \"json\": return json.dumps(self.data, indent=2, default=str)\n        if fmt == \"csv\":\n            rows = [\"probe,severity,message\"]\n            for f in self.data.get(\"findings\", []):\n                rows.append(f\"{f.get('probe','')},{f.get('severity','')},\\\"{str(f.get('message','')).replace(chr(34),chr(39))}\\\"\")\n            return \"\\n\".join(rows)\n        if fmt == \"md\":\n            lines = [f\"# {self.data.get('target','?')} — {self.data.get('mode','?')}\", \"\"]\n            by_sev = {}\n            for f in self.data.get(\"findings\", []):\n                by_sev.setdefault(f.get(\"severity\",\"INFO\"), []).append(f)\n            for sev in [\"CRITICAL\",\"HIGH\",\"MEDIUM\",\"LOW\",\"INFO\",\"ERROR\"]:\n                if sev not in by_sev: continue\n                lines.append(f\"## {sev} ({len(by_sev[sev])})\")\n                for f in by_sev[sev]:\n                    lines.append(f\"- **[{f.get('probe')}]** {f.get('message','')}\")\n                lines.append(\"\")\n            return \"\\n\".join(lines)\n        # html\n        rows = \"\".join(f\"<tr><td>{html.escape(f.get('probe',''))}</td><td>{html.escape(f.get('severity',''))}</td><td>{html.escape(str(f.get('message','')))}</td></tr>\" for f in self.data.get(\"findings\", []))\n        return f\"<html><body><h1>{html.escape(str(self.data.get('target','?')))}</h1><table border=1><tr><th>Probe</th><th>Severity</th><th>Message</th></tr>{rows}</table></body></html>\"\n",
      "probes/__init__.py": "",
