      "probes/health_endpoint.py": "def probe(cfg): return [{\"severity\":\"INFO\",\"message\":\"FastAPI scaffold ready — run: uvicorn app:app --reload\"}]\n",
      "app.py": "from fastapi import FastAPI, HTTPException, Header, Depends\nfrom pydantic import BaseModel\nimport time, hmac, hashlib, os\napp = FastAPI(title=\"Titan SaaS Starter\")\nITEMS = {}\nclass Item(BaseModel): name: str; price: float\ndef auth(x_api_key: str = Header(default=\"\")):\n  if not x_api_key or x_api_key != os.environ.get(\"API_KEY\",\"demo\"): raise HTTPException(401, \"bad key\")\n@app.get(\"/health\")\ndef health(): return {\"ok\": True, \"ts\": time.time()}\n@app.get(\"/items\")\ndef list_items(_=Depends(auth)): return list(ITEMS.values())\n@app.post(\"/items\")\ndef create(it: Item, _=Depends(auth)):\n  i = len(ITEMS)+1; ITEMS[i] = {\"id\":i, **it.model_dump()}; return ITEMS[i]\n@app.post(\"/webhook\")\ndef webhook(payload: dict, x_signature: str = Header(default=\"\")):\n  body = str(payload).encode(); sig = hmac.new(b\"hooksecret\", body, hashlib.sha256).hexdigest()\n  if not hmac.compare_digest(sig, x_signature): raise HTTPException(400, \"bad sig\")\n  return {\"ok\": True}\n",
      "Dockerfile": "FROM python:3.12-slim\nWORKDIR /app\nCOPY . .\nRUN pip install --no-cache-dir -r requirements.txt\nCMD [\"uvicorn\",\"app:app\",\"--host\",\"0.0.0.0\",\"--port\",\"8000\"]\n"
