      "core/runner.py": "\"\"\"Dispatches probes for the active mode and aggregates findings.\"\"\"\nimport importlib, asyncio\nPROBES = [\"rule_engine\",\"isolation_forest\",\"feature_engineering\"]\n\nclass Runner:\n    def __init__(self, cfg):\n        self.cfg = cfg\n        self.findings = []\n\n    async def run(self):\n        for mod_name in PROBES:\n            try:\n                mod = importlib.import_module(f\"probes.{mod_name}\")\n                res = mod.probe(self.cfg)\n                if asyncio.iscoroutine(res): res = await res\n                for r in (res or []):\n                    r.setdefault(\"probe\", mod_name)\n                    r.setdefault(\"severity\", \"INFO\")\n                    self.findings.append(r)\n            except Exception as e:\n                self.findings.append({\"probe\": mod_name, \"severity\": \"ERROR\", \"message\": f\"{type(e).__name__}: {e}\"})\n        return self.findings\n",
